pets.vue?597c","webpack://tavern_helper_template/src/规则/components/TerminalSnippets.vue?c9c9","webpack://tavern_helper_template/./src/规则/components/CoordinateTracker.vue?4df7","webpack://tavern_helper_template/src/规则/components/CoordinateTracker.vue?1c5b","webpack://tavern_helper_template/./src/规则/components/ShatteredGlassEffect.vue?7672","webpack://tavern_helper_template/src/规则/components/ShatteredGlassEffect.vue?7f66","webpack://tavern_helper_template/./src/规则/components/MagneticButton.vue?b72d","webpack://tavern_helper_template/src/规则/components/MagneticButton.vue?d3dc","src://tavern_helper_template/src/规则/components/ScrambleText.vue","webpack://tavern_helper_template/src/规则/components/ScrambleText.vue?8d70","webpack://tavern_helper_template/./src/规则/components/BlockProgress.vue?4042","webpack://tavern_helper_template/src/规则/components/BlockProgress.vue?de2c","src://tavern_helper_template/src/规则/utils/clearUiCache.ts","src://tavern_helper_template/src/规则/utils/openingStorage.ts","webpack://tavern_helper_template/./src/规则/components/OpeningForm.vue?f4f0","webpack://tavern_helper_template/src/规则/components/OpeningForm.vue?8654","webpack://tavern_helper_template/./src/规则/components/WorldLifePanel.vue?ad18","webpack://tavern_helper_template/src/规则/components/WorldLifePanel.vue?b8af","src://tavern_helper_template/src/规则/utils/randomRulesPanelSession.ts","webpack://tavern_helper_template/./src/规则/components/RandomRulesPanel.vue?2889","webpack://tavern_helper_template/src/规则/components/RandomRulesPanel.vue?5768","webpack://tavern_helper_template/./src/规则/components/EditCartModalCommitFields.vue?ee73","webpack://tavern_helper_template/src/规则/components/EditCartModalCommitFields.vue?6866","webpack://tavern_helper_template/./src/规则/components/EditCartItemEditor.vue?f88b","webpack://tavern_helper_template/src/规则/components/EditCartItemEditor.vue?90c6","webpack://tavern_helper_template/./src/规则/components/HeaderEffects.vue?6070","webpack://tavern_helper_template/src/规则/components/HeaderEffects.vue?c687","webpack://tavern_helper_template/./src/规则/components/SidebarEffects.vue?5360","webpack://tavern_helper_template/src/规则/components/SidebarEffects.vue?8e51","src://tavern_helper_template/src/规则/utils/gameTime.ts","webpack://tavern_helper_template/./src/规则/components/GameTimeDisplay.vue?ceca","webpack://tavern_helper_template/src/规则/components/GameTimeDisplay.vue?8e20","src://tavern_helper_template/src/规则/utils/gameInitializer.ts","src://tavern_helper_template/src/规则/utils/iframeHeightFix.ts","webpack://tavern_helper_template/./src/规则/App.vue?9e62","webpack://tavern_helper_template/src/规则/App.vue?7366","src://tavern_helper_template/src/规则/index.ts"],"sourcesContent":["/**\n * 角色头像子系统：与 MVU / 角色档案变量里的「头像」字段无关，可单独演进。\n * - 持久化：本页 localStorage（`tavern-phone:character-avatars`）+ 可选父窗口 postMessage 中继（跨 iframe/端口）。\n * - 按角色 id 存一条；保存时若带 displayName，会额外写入「同名键」`__byname__:规范化姓名`，\n *   同名角色可共用一张图。\n * - 规则页、手机「角色档案」等 UI 请用 `resolveCharacterAvatarFromBrowserOnly`，不要用 MVU 里的链接作 fallback。\n * - 微信联系人头像亦只用本机 overrides（`resolveCharacterAvatarFromBrowserOnly`），不再合并壳/变量里的 URL。\n */\n\nconst STORAGE_KEY = 'tavern-phone:character-avatars';\n\n/** 微信「我」页专用键（小手机）；不参与按姓名共享 */\nexport const PHONE_WECHAT_ME_AVATAR_ID = '__wechat_me__';\n\nconst NAME_OVERRIDE_PREFIX = '__byname__:';\n\n/** 用于「同名共享」：去首尾空白、中间连续空白压成单空格 */\nexport function normalizeCharacterNameForAvatar(name: string): string {\n  return String(name ?? '')\n    .trim()\n    .replace(/\\s+/g, ' ');\n}\n\nfunction nameOverrideStorageKey(displayName: string): string | null {\n  const n = normalizeCharacterNameForAvatar(displayName);\n  if (!n) {\n    return null;\n  }\n  return `${NAME_OVERRIDE_PREFIX}${n}`;\n}\n\nexport const PHONE_CHARACTER_AVATARS_CHANGED = 'tavern-phone-character-avatars-changed';\n\n/** 子 iframe → 父窗口 → 壳转发：跨端口同步头像 */\nexport const PHONE_CHARACTER_AVATAR_SYNC_TYPE = 'tavern-phone:character-avatar-sync';\n\n/** 子 iframe 挂载后向父窗口请求壳内已缓存的头像镜像（本地多端口时用） */\nexport const PHONE_CHARACTER_AVATAR_MIRROR_REQUEST = 'tavern-phone:request-avatar-mirror';\n\nfunction parseMap(raw: string | null): Record<string, string> {\n  if (!raw) {\n    return {};\n  }\n  try {\n    const p = JSON.parse(raw) as { overrides?: Record<string, unknown> };\n    const o = p?.overrides;\n    if (!o || typeof o !== 'object') {\n      return {};\n    }\n    const out: Record<string, string> = {};\n    for (const [k, v] of Object.entries(o)) {\n      if (typeof v === 'string' && v.trim()) {\n        out[k] = v.trim();\n      }\n    }\n    return out;\n  } catch {\n    return {};\n  }\n}\n\nexport function loadCharacterAvatarOverrides(): Record<string, string> {\n  try {\n    return parseMap(localStorage.getItem(STORAGE_KEY));\n  } catch {\n    return {};\n  }\n}\n\nexport function persistCharacterAvatarOverrides(map: Record<string, string>): void {\n  try {\n    if (Object.keys(map).length === 0) {\n      localStorage.removeItem(STORAGE_KEY);\n    } else {\n      localStorage.setItem(STORAGE_KEY, JSON.stringify({ overrides: map }));\n    }\n  } catch {\n    /* quota / private mode */\n  }\n  window.dispatchEvent(new Event(PHONE_CHARACTER_AVATARS_CHANGED));\n}\n\n/**\n * 仅写本 iframe 的 localStorage + 触发本页事件（用于父窗口转发回来的数据，避免再次向 parent post）\n */\nexport function applyCharacterAvatarOverrideLocal(roleId: string, avatarUrl: string): void {\n  const id = typeof roleId === 'string' ? roleId.trim() : '';\n  if (!id) {\n    return;\n  }\n  const u = typeof avatarUrl === 'string' ? avatarUrl.trim() : '';\n  const map = { ...loadCharacterAvatarOverrides() };\n  if (!u) {\n    delete map[id];\n  } else {\n    map[id] = u;\n  }\n  persistCharacterAvatarOverrides(map);\n}\n\n/** 仅通知父窗口（例如迁移完成后补发一次） */\nexport function broadcastCharacterAvatarSyncToParent(roleId: string, avatarUrl: string): void {\n  try {\n    if (typeof window === 'undefined' || window.parent === window) {\n      return;\n    }\n    window.parent.postMessage(\n      {\n        type: PHONE_CHARACTER_AVATAR_SYNC_TYPE,\n        roleId,\n        avatarUrl: typeof avatarUrl === 'string' ? avatarUrl.trim() : '',\n      },\n      '*',\n    );\n  } catch {\n    /* */\n  }\n}\n\nexport type SetCharacterAvatarOverrideOptions = {\n  /**\n   * 档案/微信里的展示姓名；与 id 同时写入时，其他相同规范化姓名的角色也会显示该头像。\n   * 不要用于 PHONE_WECHAT_ME_AVATAR_ID。\n   */\n  displayName?: string | null;\n};\n\n/** 本机覆盖：先按 id，再按同名键；否则用 remoteUrl（外链/壳下发的非 MVU 头像等） */\nexport function resolveRoleAvatarDisplay(\n  roleId: string,\n  remoteUrl: string | undefined | null,\n  overrides: Record<string, string>,\n  displayName?: string | null,\n): string {\n  const id = typeof roleId === 'string' ? roleId.trim() : '';\n  if (id && overrides[id]?.trim()) {\n    return overrides[id].trim();\n  }\n  const nk = nameOverrideStorageKey(displayName ?? '');\n  if (nk && overrides[nk]?.trim()) {\n    return overrides[nk].trim();\n  }\n  return typeof remoteUrl === 'string' ? remoteUrl.trim() : '';\n}\n\n/**\n * 与 MVU 角色档案中的头像字段解耦：只读本机 overrides + 同名键，不读变量里的 头像链接。\n */\nexport function resolveCharacterAvatarFromBrowserOnly(\n  roleId: string,\n  overrides: Record<string, string>,\n  displayName?: string | null,\n): string {\n  return resolveRoleAvatarDisplay(roleId, '', overrides, displayName);\n}\n\n/**\n * @param avatarUrl 空串则清除该 id 的覆盖；若提供 displayName 则同时清除同名键。\n */\nexport function setCharacterAvatarOverride(\n  roleId: string,\n  avatarUrl: string,\n  options?: SetCharacterAvatarOverrideOptions,\n): void {\n  const id = typeof roleId === 'string' ? roleId.trim() : '';\n  if (!id) {\n    return;\n  }\n  const u = typeof avatarUrl === 'string' ? avatarUrl.trim() : '';\n  applyCharacterAvatarOverrideLocal(id, u);\n  broadcastCharacterAvatarSyncToParent(id, u);\n\n  const nameKey = nameOverrideStorageKey(options?.displayName ?? '');\n  if (nameKey) {\n    applyCharacterAvatarOverrideLocal(nameKey, u);\n    broadcastCharacterAvatarSyncToParent(nameKey, u);\n  }\n}\n\n/**\n * 清除所有头像缓存（localStorage 中的头像覆盖）\n */\nexport function clearAllAvatarCaches(): void {\n  try {\n    localStorage.removeItem(STORAGE_KEY);\n    window.dispatchEvent(new Event(PHONE_CHARACTER_AVATARS_CHANGED));\n    console.log('[phoneCharacterAvatarStorage] 已清除所有头像缓存');\n  } catch {\n    /* ignore */\n  }\n}\n\n/**\n * 清除所有浏览器缓存（头像缓存 + 日记缓存 + 聊天记录等）\n * 这是一个破坏性的操作，用于开局重置\n */\nexport async function clearAllBrowserCaches(): Promise<void> {\n  const errors: string[] = [];\n\n  // 1. 清除头像缓存\n  try {\n    clearAllAvatarCaches();\n  } catch (e) {\n    errors.push('头像缓存清除失败');\n  }\n\n  // 2. 清除日记缓存（IndexedDB）\n  try {\n    const { clearAllDiaries } = await import('../手机/src/diaryIndexedDb');\n    await clearAllDiaries();\n  } catch (e) {\n    errors.push('日记缓存清除失败');\n  }\n\n  // 3. 清除微信聊天记录（IndexedDB）\n  try {\n    const DB_NAME = 'tavern-phone-wechat';\n    await new Promise<void>((resolve, reject) => {\n      const req = indexedDB.deleteDatabase(DB_NAME);\n      req.onsuccess = () => resolve();\n      req.onerror = () => reject(new Error('删除微信数据库失败'));\n    });\n  } catch {\n    /* 可能没有聊天记录，忽略错误 */\n  }\n\n  // 4. 清除群聊记录（IndexedDB）\n  try {\n    const DB_NAME = 'tavern-phone-groupchat';\n    await new Promise<void>((resolve, reject) => {\n      const req = indexedDB.deleteDatabase(DB_NAME);\n      req.onsuccess = () => resolve();\n      req.onerror = () => reject(new Error('删除群聊数据库失败'));\n    });\n  } catch {\n    /* 可能没有群聊记录，忽略错误 */\n  }\n\n  console.log('[phoneCharacterAvatarStorage] 已清除所有浏览器缓存');\n\n  if (errors.length > 0) {\n    throw new Error(errors.join(', '));\n  }\n}\n","/**\n * 日记存储模块\n * 用于存储和管理角色的私密日记条目\n */\n\nconst DB_NAME = 'tavern-phone-diary';\nconst DB_VERSION = 2; // 升级到v2添加全局设置表\nconst STORE_DIARIES = 'diaries';\nconst STORE_META = 'meta';\nconst STORE_SETTINGS = 'settings';\n\n/** 本地离线 scope */\nconst LOCAL_OFFLINE_SCOPE = 'local-offline';\n\n/** 全局设置键名 */\nconst GLOBAL_SETTINGS_KEY = 'global';\n\nexport interface DiaryEntry {\n  id: string;\n  characterId: string;\n  characterName: string;\n  /** 日记日期（游戏内日期） */\n  gameDate: string;\n  /** 实际创建时间戳 */\n  createdAt: number;\n  /** 日记标题 */\n  title: string;\n  /** 日记内容（最私密的心理活动） */\n  content: string;\n  /** 情绪标签 */\n  moodTags: string[];\n  /** 是否已读 */\n  isRead: boolean;\n}\n\n/** 元数据：记录每个角色上次生成日记的游戏日期 */\ninterface DiaryMeta {\n  characterId: string;\n  lastGeneratedGameDate: string;\n  lastGeneratedAt: number;\n  autoGenerateEnabled: boolean;\n}\n\nlet dbPromise: Promise<IDBDatabase> | null = null;\n\nfunction openDb(): Promise<IDBDatabase> {\n  if (!dbPromise) {\n    dbPromise = new Promise((resolve, reject) => {\n      const req = indexedDB.open(DB_NAME, DB_VERSION);\n      req.onerror = () => {\n        dbPromise = null;\n        reject(req.error ?? new Error('IndexedDB open failed'));\n      };\n      req.onsuccess = () => resolve(req.result);\n      req.onupgradeneeded = event => {\n        const db = (event.target as IDBOpenDBRequest).result;\n        if (!db.objectStoreNames.contains(STORE_DIARIES)) {\n          const store = db.createObjectStore(STORE_DIARIES, { keyPath: 'id' });\n          store.createIndex('characterId', 'characterId', { unique: false });\n          store.createIndex('gameDate', 'gameDate', { unique: false });\n        }\n        if (!db.objectStoreNames.contains(STORE_META)) {\n          db.createObjectStore(STORE_META, { keyPath: 'characterId' });\n        }\n        // v2: 添加全局设置表\n        if (!db.objectStoreNames.contains(STORE_SETTINGS)) {\n          db.createObjectStore(STORE_SETTINGS, { keyPath: 'key' });\n        }\n      };\n    });\n  }\n  return dbPromise;\n}\n\n/** 生成唯一ID */\nfunction generateId(): string {\n  return `${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;\n}\n\n/**\n * 保存日记条目\n */\nexport async function saveDiary(entry: Omit<DiaryEntry, 'id' | 'createdAt'>): Promise<DiaryEntry> {\n  const db = await openDb();\n  const fullEntry: DiaryEntry = {\n    ...entry,\n    id: generateId(),\n    createdAt: Date.now(),\n  };\n\n  await new Promise<void>((resolve, reject) => {\n    const tx = db.transaction(STORE_DIARIES, 'readwrite');\n    tx.objectStore(STORE_DIARIES).put(fullEntry);\n    tx.oncomplete = () => resolve();\n    tx.onerror = () => reject(tx.error);\n  });\n\n  return fullEntry;\n}\n\n/**\n * 获取角色的所有日记（按时间倒序）\n */\nexport async function getDiariesByCharacter(characterId: string): Promise<DiaryEntry[]> {\n  const db = await openDb();\n  return new Promise((resolve, reject) => {\n    const out: DiaryEntry[] = [];\n    const tx = db.transaction(STORE_DIARIES, 'readonly');\n    const store = tx.objectStore(STORE_DIARIES);\n    const index = store.index('characterId');\n    const range = IDBKeyRange.only(characterId);\n    const req = index.openCursor(range, 'prev');\n\n    req.onsuccess = () => {\n      const cursor = req.result;\n      if (!cursor) {\n        resolve(out);\n        return;\n      }\n      out.push(cursor.value as DiaryEntry);\n      cursor.continue();\n    };\n    req.onerror = () => reject(req.error);\n  });\n}\n\n/**\n * 获取所有日记（按时间倒序）\n */\nexport async function getAllDiaries(): Promise<DiaryEntry[]> {\n  const db = await openDb();\n  return new Promise((resolve, reject) => {\n    const out: DiaryEntry[] = [];\n    const tx = db.transaction(STORE_DIARIES, 'readonly');\n    const store = tx.objectStore(STORE_DIARIES);\n    const req = store.openCursor(null, 'prev');\n\n    req.onsuccess = () => {\n      const cursor = req.result;\n      if (!cursor) {\n        resolve(out);\n        return;\n      }\n      out.push(cursor.value as DiaryEntry);\n      cursor.continue();\n    };\n    req.onerror = () => reject(req.error);\n  });\n}\n\n/**\n * 标记日记为已读\n */\nexport async function markDiaryAsRead(diaryId: string): Promise<void> {\n  const db = await openDb();\n  return new Promise((resolve, reject) => {\n    const tx = db.transaction(STORE_DIARIES, 'readwrite');\n    const store = tx.objectStore(STORE_DIARIES);\n    const req = store.get(diaryId);\n\n    req.onsuccess = () => {\n      const entry = req.result as DiaryEntry | undefined;\n      if (entry) {\n        entry.isRead = true;\n        store.put(entry);\n      }\n      resolve();\n    };\n    req.onerror = () => reject(req.error);\n  });\n}\n\n/**\n * 删除日记\n */\nexport async function deleteDiary(diaryId: string): Promise<void> {\n  const db = await openDb();\n  return new Promise<void>((resolve, reject) => {\n    const tx = db.transaction(STORE_DIARIES, 'readwrite');\n    tx.objectStore(STORE_DIARIES).delete(diaryId);\n    tx.oncomplete = () => resolve();\n    tx.onerror = () => reject(tx.error);\n  });\n}\n\n/**\n * 获取角色的元数据\n */\nexport async function getDiaryMeta(characterId: string): Promise<DiaryMeta | null> {\n  const db = await openDb();\n  return new Promise((resolve, reject) => {\n    const tx = db.transaction(STORE_META, 'readonly');\n    const req = tx.objectStore(STORE_META).get(characterId);\n    req.onsuccess = () => {\n      const result = req.result as DiaryMeta | undefined;\n      resolve(result ?? null);\n    };\n    req.onerror = () => reject(req.error);\n  });\n}\n\n/**\n * 保存角色的元数据\n */\nexport async function saveDiaryMeta(meta: DiaryMeta): Promise<void> {\n  const db = await openDb();\n  return new Promise<void>((resolve, reject) => {\n    const tx = db.transaction(STORE_META, 'readwrite');\n    tx.objectStore(STORE_META).put(meta);\n    tx.oncomplete = () => resolve();\n    tx.onerror = () => reject(tx.error);\n  });\n}\n\n/**\n * 检查今天是否需要自动生成日记\n * @param characterId 角色ID\n * @param currentGameDate 当前游戏日期\n * @returns 是否需要生成\n */\nexport async function shouldAutoGenerateDiary(\n  characterId: string,\n  currentGameDate: string,\n): Promise<boolean> {\n  const meta = await getDiaryMeta(characterId);\n  if (!meta?.autoGenerateEnabled) {\n    return false;\n  }\n  return meta.lastGeneratedGameDate !== currentGameDate;\n}\n\n/**\n * 更新上次生成日期\n */\nexport async function updateLastGeneratedDate(\n  characterId: string,\n  gameDate: string,\n): Promise<void> {\n  const meta = await getDiaryMeta(characterId);\n  const newMeta: DiaryMeta = {\n    characterId,\n    lastGeneratedGameDate: gameDate,\n    lastGeneratedAt: Date.now(),\n    autoGenerateEnabled: meta?.autoGenerateEnabled ?? true,\n  };\n  await saveDiaryMeta(newMeta);\n}\n\n/**\n * 切换自动生成功能\n */\nexport async function toggleAutoGenerate(characterId: string, enabled: boolean): Promise<void> {\n  const meta = await getDiaryMeta(characterId);\n  const newMeta: DiaryMeta = {\n    characterId,\n    lastGeneratedGameDate: meta?.lastGeneratedGameDate ?? '',\n    lastGeneratedAt: meta?.lastGeneratedAt ?? 0,\n    autoGenerateEnabled: enabled,\n  };\n  await saveDiaryMeta(newMeta);\n}\n\n/**\n * 获取未读日记数量\n */\nexport async function getUnreadDiaryCount(): Promise<number> {\n  const all = await getAllDiaries();\n  return all.filter(d => !d.isRead).length;\n}\n\n// ==================== 全局自动更新设置 ====================\n\n/** 全局自动更新设置 */\nexport interface DiaryGlobalSettings {\n  key: 'global';\n  /** 自动更新是否启用 */\n  autoUpdateEnabled: boolean;\n  /** 间隔天数（1-30天） */\n  intervalDays: number;\n  /** 上次检查的游戏日期 */\n  lastCheckedGameDate: string;\n  /** 最后更新时间戳 */\n  updatedAt: number;\n}\n\n/**\n * 获取全局设置\n */\nexport async function getDiaryGlobalSettings(): Promise<DiaryGlobalSettings> {\n  const db = await openDb();\n  return new Promise((resolve, reject) => {\n    const tx = db.transaction(STORE_SETTINGS, 'readonly');\n    const req = tx.objectStore(STORE_SETTINGS).get(GLOBAL_SETTINGS_KEY);\n    req.onsuccess = () => {\n      const result = req.result as DiaryGlobalSettings | undefined;\n      resolve(result ?? {\n        key: 'global',\n        autoUpdateEnabled: false,\n        intervalDays: 1,\n        lastCheckedGameDate: '',\n        updatedAt: 0,\n      });\n    };\n    req.onerror = () => reject(req.error);\n  });\n}\n\n/**\n * 保存全局设置\n */\nexport async function saveDiaryGlobalSettings(settings: Omit<DiaryGlobalSettings, 'key' | 'updatedAt'>): Promise<void> {\n  const db = await openDb();\n  const fullSettings: DiaryGlobalSettings = {\n    ...settings,\n    key: 'global',\n    updatedAt: Date.now(),\n  };\n  return new Promise<void>((resolve, reject) => {\n    const tx = db.transaction(STORE_SETTINGS, 'readwrite');\n    tx.objectStore(STORE_SETTINGS).put(fullSettings);\n    tx.oncomplete = () => resolve();\n    tx.onerror = () => reject(tx.error);\n  });\n}\n\n/**\n * 切换自动更新功能\n */\nexport async function toggleAutoUpdate(enabled: boolean): Promise<void> {\n  const settings = await getDiaryGlobalSettings();\n  await saveDiaryGlobalSettings({\n    ...settings,\n    autoUpdateEnabled: enabled,\n  });\n}\n\n/**\n * 设置更新间隔天数\n */\nexport async function setAutoUpdateIntervalDays(days: number): Promise<void> {\n  const settings = await getDiaryGlobalSettings();\n  await saveDiaryGlobalSettings({\n    ...settings,\n    intervalDays: Math.max(1, Math.min(30, days)),\n  });\n}\n\n/**\n * 更新最后检查日期\n */\nexport async function updateLastCheckedDate(gameDate: string): Promise<void> {\n  const settings = await getDiaryGlobalSettings();\n  await saveDiaryGlobalSettings({\n    ...settings,\n    lastCheckedGameDate: gameDate,\n  });\n}\n\n/**\n * 清空所有日记数据（用于重置）\n */\nexport async function clearAllDiaries(): Promise<void> {\n  const db = await openDb();\n  return new Promise<void>((resolve, reject) => {\n    const tx = db.transaction([STORE_DIARIES, STORE_META], 'readwrite');\n    tx.objectStore(STORE_DIARIES).clear();\n    tx.objectStore(STORE_META).clear();\n    tx.oncomplete = () => resolve();\n    tx.onerror = () => reject(tx.error);\n  });\n}\n","import { shallowRef, watchEffect, readonly, watch, customRef, getCurrentScope, onScopeDispose, effectScope, getCurrentInstance, hasInjectionContext, inject, provide, ref, isRef, unref, toValue as toValue$1, computed, reactive, toRefs as toRefs$1, toRef as toRef$1, shallowReadonly, onBeforeMount, nextTick, onBeforeUnmount, onMounted, onUnmounted, isReactive } from 'vue';\n\nfunction computedEager(fn, options) {\n  var _a;\n  const result = shallowRef();\n  watchEffe