 import('./dialogAndVariable');\n    messageText = await submitAddRegion(form.regionName, form.regionDetail, form.regionFirstRuleName);\n  } else if (type === 'edit_region' && (p?.id ?? p?.name)) {\n    const { submitEditRegion } = await import('./dialogAndVariable');\n    messageText = await submitEditRegion(String(p.id ?? p.name), form.regionName, form.regionDetail);\n  } else if (type === 'add_region_rule' && (p?.id ?? p?.name ?? p?.regionId ?? p?.regionName)) {\n    const { submitAddRegionalRule } = await import('./dialogAndVariable');\n    const regionId = String(p.id ?? p.name ?? p.regionId ?? p.regionName);\n    const regionName = String(p.name ?? p.regionName ?? form.regionName);\n    messageText = await submitAddRegionalRule(regionId, regionName, form.regionRuleName, form.regionRuleDetail);\n  } else if (\n    type === 'edit_region_rule' &&\n    (p?.regionId ?? p?.regionName) &&\n    (p as { rule?: { id?: string; title?: string } })?.rule &&\n    ((p as { rule: { id?: string; title?: string } }).rule.id ??\n      (p as { rule: { id?: string; title?: string } }).rule.title)\n  ) {\n    const { submitEditRegionalRule } = await import('./dialogAndVariable');\n    const rule = (p as { rule: { id?: string; title?: string }; regionId?: string; regionName?: string }).rule;\n    messageText = await submitEditRegionalRule(\n      String(p.regionId ?? p.regionName),\n      String(p.regionName),\n      String(rule.id ?? rule.title),\n      form.regionRuleName,\n      form.regionRuleDetail,\n    );\n  } else if (type === 'add_personal_rule') {\n    const { submitAddPersonalRule } = await import('./dialogAndVariable');\n    messageText = await submitAddPersonalRule(form.personalRuleCharacter, form.personalRuleDetail);\n  } else if (type === 'edit_personal_rule' && (p?.id ?? p?.title ?? p?.character)) {\n    const { submitEditPersonalRule } = await import('./dialogAndVariable');\n    messageText = await submitEditPersonalRule(\n      String(p.id ?? p.title ?? p.character),\n      form.personalRuleCharacter,\n      form.personalRuleDetail,\n    );\n  } else if (type === 'edit_character_mind' && p?.characterId) {\n    const { submitEditCharacterPsych } = await import('./dialogAndVariable');\n    messageText = await submitEditCharacterPsych(String(p.characterId), {\n      thought: form.characterPsychThought,\n      traitsText: form.characterPsychTraits,\n    });\n  } else if (type === 'edit_character_fetish' && p?.characterId) {\n    const {\n      submitEditCharacterPsych,\n      updateCharacterFetishDetails,\n      updateCharacterSensitivePartDetails,\n      formatFetishDetailMessage,\n      formatSensitivePartDetailMessage,\n    } = await import('./dialogAndVariable');\n    const characterId = String(p.characterId);\n    messageText = await submitEditCharacterPsych(characterId, {\n      fetishesText: form.characterPsychFetishes,\n      sensitivePartsText: form.characterPsychSensitiveParts,\n      hiddenFetish: form.characterPsychHiddenFetish,\n    });\n\n    const validFetishDetails = form.fetishDetails?.filter(f => f.name?.trim()) ?? [];\n    if (validFetishDetails.length > 0) {\n      const mapped = validFetishDetails.map(f => ({\n        name: f.name.trim(),\n        level: f.level ?? 1,\n        description: f.description ?? '',\n        justification: f.justification ?? '',\n      }));\n      updateCharacterFetishDetails(characterId, mapped);\n      messageText += '\\n\\n' + formatFetishDetailMessage(characterId, mapped);\n    }\n\n    const validSensitivePartDetails = form.sensitivePartDetails?.filter(x => x.name?.trim()) ?? [];\n    if (validSensitivePartDetails.length > 0) {\n      const mapped = validSensitivePartDetails.map(x => ({\n        name: x.name.trim(),\n        level: x.level ?? 1,\n        reaction: x.reaction ?? '',\n        devDetails: x.devDetails ?? '',\n      }));\n      updateCharacterSensitivePartDetails(characterId, mapped);\n      messageText += '\\n\\n' + formatSensitivePartDetailMessage(characterId, mapped);\n    }\n  } else if (type === 'edit_identity_tags' && p?.characterId) {\n    const { updateCharacterIdentityTags, formatIdentityTagsMessage } = await import('./dialogAndVariable');\n    const validTags = form.identityTags?.filter(t => t.category?.trim() && t.value?.trim()) ?? [];\n    const tagsObj: Record<string, string> = {};\n    for (const t of validTags) {\n      tagsObj[t.category.trim()] = t.value.trim();\n    }\n    const characterId = String(p.characterId);\n    updateCharacterIdentityTags(characterId, tagsObj);\n    messageText = formatIdentityTagsMessage(characterId, tagsObj);\n  } else if (type === 'edit_avatar' && p?.characterId) {\n    const { submitEditCharacterAvatar } = await import('./dialogAndVariable');\n    const store = useDataStore();\n    const raw = store.data.角色档案?.[String(p.characterId)] as Record<string, unknown> | undefined;\n    const displayName = String(raw?.姓名 ?? raw?.name ?? '').trim();\n    await submitEditCharacterAvatar(String(p.characterId), form.avatarUrl, displayName || null);\n    return '';\n  } else {\n    throw new Error(`未知的弹窗类型或缺少数据: ${type}`);\n  }\n\n  return messageText;\n}\n\nexport async function applyEditCartAction(action: EditCartAction): Promise<string> {\n  const m = await import('./dialogAndVariable');\n\n  switch (action.kind) {\n    case 'archive_world_rule':\n      await m.submitArchiveWorldRule(action.title);\n      return '';\n    case 'archive_region':\n      await m.submitArchiveRegion(action.name);\n      return '';\n    case 'archive_personal_rule':\n      await m.submitArchivePersonalRule(action.idOrTitle, action.characterName, action.ruleSummary);\n      return '';\n    case 'character_basic':\n      return await m.submitEditCharacterBasic(action.characterId, action.data);\n    case 'delete_character':\n      return await m.submitDeleteCharacter(action.characterId, action.characterName);\n    case 'random_add_world':\n      return await m.submitAddWorldRule(action.title, action.desc);\n    case 'random_add_regional':\n      return await m.submitAddRegionalRule(\n        action.regionId,\n        action.regionName,\n        action.title,\n        action.desc,\n      );\n    case 'random_add_personal':\n      return await m.submitAddPersonalRule(action.target, action.detail);\n    case 'modal_commit':\n      return await runModalCommit(action.modalType, action.form, action.payload);\n    default: {\n      const _exhaustive: never = action;\n      void _exhaustive;\n      return '';\n    }\n  }\n}\n","import { defineStore } from 'pinia';\nimport { ref, computed } from 'vue';\nimport type { EditCartItem } from '../types/editCart';\nimport { applyEditCartAction } from '../utils/editCartApply';\n\nconst CAT_ORDER = ['world', 'region', 'character', 'personal', 'avatar'] as const;\n\nexport const useEditCartStore = defineStore('ruleEditCart', () => {\n  const items = ref<EditCartItem[]>([]);\n\n  const pendingCount = computed(() => items.value.length);\n\n  function addOrReplaceItem(item: EditCartItem) {\n    const i = items.value.findIndex(x => x.dedupeKey === item.dedupeKey);\n    if (i >= 0) {\n      items.value.splice(i, 1, item);\n    } else {\n      items.value.push(item);\n    }\n  }\n\n  /** 编辑后写回：先移除原 id，再按 dedupeKey 合并（与同键覆盖策略一致） */\n  function replaceItemAfterEdit(item: EditCartItem) {\n    items.value = items.value.filter(x => x.id !== item.id);\n    addOrReplaceItem(item);\n  }\n\n  function removeItem(id: string) {\n    items.value = items.value.filter(x => x.id !== id);\n  }\n\n  function clear() {\n    items.value = [];\n  }\n\n  function sortedItems(): EditCartItem[] {\n    const buckets = new Map<string, EditCartItem[]>();\n    for (const c of CAT_ORDER) {\n      buckets.set(c, []);\n    }\n    for (const it of items.value) {\n      buckets.get(it.category)?.push(it);\n    }\n    return CAT_ORDER.flatMap(c => buckets.get(c) ?? []);\n  }\n\n  /**\n   * 按分区顺序执行；全部成功后清空购物车并合并说明写入输入框。\n   * 中途失败：已执行项已从购物车移除，未执行项保留。\n   */\n  async function applyAll(copyToInput: (text: string, mode: 'append' | 'replace') => void): Promise<boolean> {\n    const list = sortedItems();\n    const fragments: string[] = [];\n    for (let i = 0; i < list.length; i++) {\n      try {\n        const t = (await applyEditCartAction(list[i].action)).trim();\n        if (t) {\n          fragments.push(t);\n        }\n      } catch (e) {\n        console.error('[editCart] applyAll 在第', i + 1, '项失败:', e);\n        const keepIds = new Set(list.slice(i).map(x => x.id));\n        items.value = items.value.filter(x => keepIds.has(x.id));\n        toastr.error(`批量提交在第 ${i + 1} 项失败：${e instanceof Error ? e.message : String(e)}`);\n        return false;\n      }\n    }\n    clear();\n    if (fragments.length > 0) {\n      copyToInput(fragments.join('\\n\\n---\\n\\n'), 'append');\n    }\n    return true;\n  }\n\n  return {\n    items,\n    pendingCount,\n    addOrReplaceItem,\n    replaceItemAfterEdit,\n    removeItem,\n    clear,\n    sortedItems,\n    applyAll,\n  };\n});\n","/**\n * 编辑购物车：开关判断、入队 vs 立即执行、构造条目\n */\nimport { klona } from 'klona';\nimport { useEditCartStore } from '../stores/editCart';\nimport type { EditCartCategory, EditCartItem, EditCartModalForm } from '../types/editCart';\nimport { getOtherSettings } from './otherSettings';\n\nexport function isEditCartEnabled(): boolean {\n  return getOtherSettings().enableEditStagingCart === true;\n}\n\nfunction newId(): string {\n  return typeof crypto !== 'undefined' && crypto.randomUUID\n    ? crypto.randomUUID()\n    : `cart-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;\n}\n\nexport function categoryForModalType(modalType: string): EditCartCategory {\n  switch (modalType) {\n    case 'add_world_rule':\n    case 'edit_world_rule':\n      return 'world';\n    case 'add_region':\n    case 'edit_region':\n    case 'add_region_rule':\n    case 'edit_region_rule':\n      return 'region';\n    case 'add_character':\n    case 'edit_character_mind':\n    case 'edit_character_fetish':\n    case 'edit_identity_tags':\n      return 'character';\n    case 'add_personal_rule':\n    case 'edit_personal_rule':\n      return 'personal';\n    case 'edit_avatar':\n      return 'avatar';\n    default:\n      return 'character';\n  }\n}\n\nexport function buildModalCartItem(\n  modalType: string,\n  form: EditCartModalForm,\n  payload: Record<string, unknown> | null,\n  label: string,\n  dedupeKey: string,\n): EditCartItem {\n  return {\n    id: newId(),\n    dedupeKey,\n    label,\n    category: categoryForModalType(modalType),\n    action: {\n      kind: 'modal_commit',\n      modalType,\n      form: klona(form) as EditCartModalForm,\n      payload: payload ? (klona(payload) as Record<string, unknown>) : null,\n    },\n  };\n}\n\nexport function buildArchiveWorldItem(title: string): EditCartItem {\n  return {\n    id: newId(),\n    dedupeKey: `archive_world:${title}`,\n    label: `归档世界规则：${title}`,\n    category: 'world',\n    action: { kind: 'archive_world_rule', title },\n  };\n}\n\nexport function buildArchiveRegionItem(name: string): EditCartItem {\n  return {\n    id: newId(),\n    dedupeKey: `archive_region:${name}`,\n    label: `归档区域：${name}`,\n    category: 'region',\n    action: { kind: 'archive_region', name },\n  };\n}\n\nexport function buildArchivePersonalItem(\n  idOrTitle: string,\n  characterName?: string,\n  ruleSummary?: string,\n  label?: string,\n): EditCartItem {\n  const key = `archive_personal:${idOrTitle}:${characterName ?? ''}`;\n  return {\n    id: newId(),\n    dedupeKey: key,\n    label: label ?? `归档个人规则：${characterName ?? idOrTitle}`,\n    category: 'personal',\n    action: { kind: 'archive_personal_rule', idOrTitle, characterName, ruleSummary },\n  };\n}\n\nexport function buildCharacterBasicItem(\n  characterId: string,\n  data: Record<string, string | number | undefined>,\n  displayName: string,\n): EditCartItem {\n  return {\n    id: newId(),\n    dedupeKey: `character_basic:${characterId}`,\n    label: `编辑角色基础信息：${displayName || characterId}`,\n    category: 'character',\n    action: { kind: 'character_basic', characterId, data },\n  };\n}\n\nexport function buildDeleteCharacterItem(characterId: string, characterName: string): EditCartItem {\n  return {\n    id: newId(),\n    dedupeKey: `delete_character:${characterId}`,\n    label: `删除角色：${characterName}`,\n    category: 'character',\n    action: { kind: 'delete_character', characterId, characterName },\n  };\n}\n\nexport function buildArchivePersonalFromPayload(payload: Record<string, unknown>): EditCartItem {\n  const id = String(payload.id ?? payload.title ?? payload.character ?? '');\n  const character = payload.character != null ? String(payload.character) : undefined;\n  const title = payload.title != null ? String(payload.title) : undefined;\n  const ruleSummary = title !== character ? title : undefined;\n  return buildArchivePersonalItem(id, character, ruleSummary);\n}\n\nexport function buildRandomWorldItem(title: string, desc: string): EditCartItem {\n  return {\n    id: newId(),\n    dedupeKey: `random_world:${title}`,\n    label: `随机规则 → 世界：${title}`,\n    category: 'world',\n    action: { kind: 'random_add_world', title, desc },\n  };\n}\n\nexport function buildRandomRegionalItem(\n  regionId: string,\n  regionName: string,\n  title: string,\n  desc: string,\n): EditCartItem {\n  return {\n    id: newId(),\n    dedupeKey: `random_regional:${regionId}:${title}`,\n    label: `随机规则 → 区域「${regionName}」：${title}`,\n    category: 'region',\n    action: { kind: 'random_add_regional', regionId, regionName, title, desc },\n  };\n}\n\nexport function buildRandomPersonalItem(target: string, detail: string): EditCartItem {\n  return {\n    id: newId(),\n    dedupeKey: `random_personal:${target}:${detail.slice(0, 40)}`,\n    label: `随机规则 → 个人：${target}`,\n    category: 'personal',\n    action: { kind: 'random_add_personal', target, detail },\n  };\n}\n\nexport function stageItem(item: EditCartItem): void {\n  const cart = useEditCartStore();\n  cart.addOrReplaceItem(item);\n  toastr.info(`已加入暂存（共 ${cart.pendingCount} 项），请打开购物车统一提交`);\n}\n\n/**\n * 根据 action 内容重算 label / dedupeKey / category（编辑暂存项保存时调用，保留 item.id）\n */\nexport function refreshEditCartItem(item: EditCartItem): EditCartItem {\n  const a = item.action;\n  switch (a.kind) {\n    case 'archive_world_rule':\n      return {\n        ...item,\n        dedupeKey: `archive_world:${a.title}`,\n        label: `归档世界规则：${a.title}`,\n        category: 'world',\n        action: { kind: 'archive_world_rule', title: a.title },\n      };\n    case 'archive_region':\n      return {\n        ...item,\n        dedupeKey: `archive_region:${a.name}`,\n        label: `归档区域：${a.name}`,\n        category: 'region',\n        action: { kind: 'archive_region', name: a.name },\n      };\n    case 'archive_personal_rule': {\n      const key = `archive_personal:${a.idOrTitle}:${a.characterName ?? ''}`;\n      return {\n        ...item,\n        dedupeKey: key,\n        label: `归档个人规则：${a.characterName ?? a.idOrTitle}`,\n        category: 'personal',\n        action: { ...a },\n      };\n    }\n    case 'character_basic': {\n      const dn = String(a.data.name ?? '').trim() || item.label;\n      return {\n        ...item,\n        dedupeKey: `character_basic:${a.characterId}`,\n        label: `编辑角色基础信息：${dn || a.characterId}`,\n        category: 'character',\n        action: { kind: 'character_basic', characterId: a.characterId, data: { ...a.data } },\n      };\n    }\n    case 'delete_character':\n      return {\n        ...item,\n        dedupeKey: `delete_character:${a.characterId}`,\n        label: `删除角色：${a.characterName}`,\n        category: 'character',\n        action: { kind: 'delete_character', characterId: a.characterId, characterName: a.characterName },\n      };\n    case 'random_add_world':\n      return {\n        ...item,\n        dedupeKey: `random_world:${a.title}`,\n        label: `随机规则 → 世界：${a.title}`,\n        category: 'world',\n        