 事件日志数据\n        const eventLogs = [\n            { time: '00:00', msg: 'System initialized.', highlight: false },\n            { time: '00:01', msg: 'Reality anchor stabilized.', highlight: false },\n            { time: '00:03', msg: 'Awaiting user input...', highlight: true },\n        ];\n        // 底部工具按钮\n        const bottomTools = [\n            { action: 'preset', label: '读取开场预设', icon: 'fa-solid fa-database', handler: () => presetPickerOpen.value = true },\n            { action: 'export', label: '导出 JSON', icon: 'fa-solid fa-upload', handler: onExportJson },\n            { action: 'import', label: '导入 JSON', icon: 'fa-solid fa-download', handler: onPickImportJson },\n        ];\n        // 随机高度（数据条动画）\n        const getRandomHeight = () => Math.floor(Math.random() * 30) + 10;\n        // 页面状态\n        const currentPage = ref('cover');\n        const isFlipping = ref(false);\n        // 场景时代类型\n        const sceneOptions = [\n            { id: 'school', name: '圣华女子学院', desc: '一所 prestigious 的贵族女子学校，学生们都在这里接受精英教育', icon: 'fa-solid fa-school', era: 'modern' },\n            { id: 'office', name: '未来科技公司', desc: '一家高科技公司，员工们在这里开发着改变世界的技术', icon: 'fa-solid fa-building', era: 'modern' },\n            { id: 'hospital', name: '圣玛利亚医院', desc: '一家大型综合医院，各种离奇的故事在这里发生', icon: 'fa-solid fa-hospital', era: 'modern' },\n            { id: 'apartment', name: '樱庄公寓', desc: '一栋普通的公寓楼，住着形形色色的租客', icon: 'fa-solid fa-house-chimney', era: 'modern' },\n            { id: 'castle', name: '夜之城堡', desc: '一座神秘的古老城堡，传说中住着吸血鬼', icon: 'fa-solid fa-chess-rook', era: 'medieval' },\n            { id: 'fantasy_tavern', name: '异世界冒险者酒馆', desc: '位于异世界的冒险者聚集地，各种族在此交汇', icon: 'fa-solid fa-wine-glass', era: 'fantasy' },\n            { id: 'cyberpunk_city', name: '霓虹城', desc: '2077年的赛博朋克都市，高科技与低生活的交汇点', icon: 'fa-solid fa-city', era: 'future' },\n            { id: 'ancient_palace', name: '大唐宫廷', desc: '盛唐时期的皇家宫殿，繁华与权谋交织', icon: 'fa-solid fa-landmark', era: 'ancient' },\n        ];\n        // 预设规则\n