}时${pad(分)}分`;\n        case 'YYYY年MM月DD日 HH:mm':\n            return `${年}年${pad(月)}月${pad(日)}日 ${pad(时)}:${pad(分)}`;\n        case 'MM月DD日 HH:mm':\n            return `${pad(月)}月${pad(日)}日 ${pad(时)}:${pad(分)}`;\n        case '相对描述':\n            return getTimeRelativeDescription(time);\n        default:\n            return `${年}-${pad(月)}-${pad(日)} ${pad(时)}:${pad(分)}`;\n    }\n}\n/**\n * 获取时间的相对描述（早晨/上午/下午/晚上/深夜）\n */\nexport function getTimeRelativeDescription(time) {\n    const { 时, 分 } = time;\n    const totalMinutes = 时 * 60 + 分;\n    // 5:00 - 8:00: 清晨\n    if (totalMinutes >= 300 && totalMinutes < 480) {\n        return '清晨';\n    }\n    // 8:00 - 11:30: 上午\n    if (totalMinutes >= 480 && totalMinutes < 690) {\n        return '上午';\n    }\n    // 11:30 - 13:30: 中午\n    if (totalMinutes >= 690 && totalMinutes < 810) {\n        return '中午';\n    }\n    // 13:30 - 17:30: 下午\n    if (totalMinutes >= 810 && totalMinutes < 1050) {\n        return '下午';\n    }\n    // 17:30 - 19:30: 傍晚\n    if (totalMinutes >= 1050 && totalMinutes < 1170) {\n        return '傍晚';\n    }\n    // 19:30 - 22:00: 晚上\n    if (totalMinutes >= 1170 && totalMinutes < 1320) {\n        return '晚上';\n    }\n    // 22:00 - 24:00: 深夜\n    if (totalMinutes >= 1320 || totalMinutes < 300) {\n        return '深夜';\n    }\n    return '';\n}\n/**\n * 获取详细时间段描述（带具体时间）\n */\nexport function getDetailedTimeDescription(time) {\n    const period = getTimeRelativeDescription(time);\n    const format = formatGameTime(time, 'HH:mm');\n    return `${period} ${format}`;\n}\n/**\n * 推进游戏时间\n * @param minutes 要推进的分钟数\n */\nexport function advanceGameTime(minutes) {\n    const store = useDataStore();\n    const gameTime = store.data.游戏时间;\n    if (!gameTime) {\n        console.error('[游戏时间] 游戏时间变量未定义');\n        return;\n    }\n    // 推进时间\n    gameTime.分 += Math.round(minutes);\n    console.log(`[游戏时间] 推进了 ${minutes} 分钟，当前时间:`, formatGameTime(gameTime));\n}\n/**\n * 设置游戏时间到指定值\n */\nexport function setGameTime(newTime) {\n    const store = useDataStore();\n    const gameTime = store.data.游戏时间;\n    if (!gameTime) {\n        console.error('[游戏时间] 游戏时间变量未定义');\n        return;\n    }\n    // 更新提供的字段\n    if (newTime.年 !== undefined)\n        gameTime.年 = newTime.年;\n    if (newTime.月 !== undefined)\n        gameTime.月 = newTime.月;\n    if (newTime.日 !== undefined)\n        gameTime.日 = newTime.日;\n    if (newTime.时 !== undefined)\n        gameTime.时 = newTime.时;\n    if (newTime.分 !== undefined)\n        gameTime.分 = newTime.分;\n    console.log(`[游戏时间] 时间已设置:`, formatGameTime(gameTime));\n}\n/**\n * 获取游戏时间的响应式引用（用于Vue组件）\n */\nexport function useGameTime() {\n    const store = useDataStore();\n    return computed({\n        get: () => {\n            const gameTime = store.data.游戏时间;\n            return {\n                年: gameTime?.年 ?? 2026,\n                月: gameTime?.月 ?? 4,\n                日: gameTime?.日 ?? 4,\n                时: gameTime?.时 ?? 12,\n                分: gameTime?.分 ?? 0,\n            };\n        },\n        set: (newTime) => {\n            setGameTime(newTime);\n        },\n    });\n}\n/**\n * 计算两个时间点的差值（以分钟为单位）\n */\nexport function getTimeDifferenceInMinutes(time1, time2) {\n    // 每月按31天计算，与schema保持一致\n    const 每月天数 = 31;\n    const toTotalMinutes = (t) => ((((t.年 * 12) + t.月) * 每月天数) + t.日) * 24 * 60 + t.时 * 60 + t.分;\n    return Math.abs(toTotalMinutes(time1) - toTotalMinutes(time2));\n}\n/**\n * 判断是否是同一天\n */\nexport function isSameDay(time1, time2) {\n    return time1.年 === time2.年 && time1.月 === time2.月 && time1.日 === time2.日;\n}\n/**\n * 判断是否是白天（6:00 - 18:00）\n */\nexport function isDaytime(time) {\n    return time.时 >= 6 && time.时 < 18;\n}\n/**\n * 判断是否是夜晚（18:00 - 6:00）\n */\nexport function isNighttime(time) {\n    return !isDaytime(time);\n}\n/**\n * 获取星期几（基于日期计算，0=周日，1=周一...）\n */\nexport function getDayOfWeek(time) {\n    // 使用基姆拉尔森计算公式（Zeller公式的变体）\n    const { 年, 月, 日 } = time;\n    let y = 年;\n    let m = 月;\n    let d = 日;\n    if (m < 3) {\n        m += 12;\n        y -= 1;\n    }\n    const c = Math.floor(y / 100);\n    const y2 = y % 100;\n    const w = (c / 4 - 2 * c + y2 + y2 / 4 + 13 * (m + 1) / 5 + d - 1) % 7;\n    return Math.floor(w + 7) % 7;\n}\n/**\n * 获取星期几的中文描述\n */\nexport function getDayOfWeekChinese(time) {\n    const days = ['周日', '周一', '周二', '周三', '周四', '周五', '周六'];\n    return days[getDayOfWeek(time)];\n}\n/**\n * 获取完整时间显示（用于手机锁屏等场景）\n */\nexport function getFullTimeDisplay(time) {\n    const dateStr = formatGameTime(time, 'YYYY年MM月DD日');\n    const weekStr = getDayOfWeekChinese(time);\n    const timeStr = formatGameTime(time, 'HH:mm');\n    return `${dateStr} ${weekStr} ${timeStr}`;\n}\n","import { defineComponent as _defineComponent } from 'vue';\nimport { createElementVNode as _createElementVNode, toDisplayString as _toDisplayString, openBlock as _openBlock, createElementBlock as _createElementBlock, createCommentVNode as _createCommentVNode, normalizeClass as _normalizeClass } from \"vue\";\nconst _hoisted_1 = { class: \"time-main\" };\nconst _hoisted_2 = { class: \"time-text\" };\nconst _hoisted_3 = {\n    key: 0,\n    class: \"week-day\"\n};\nimport { computed } from 'vue';\nimport { useGameTime } from '../store';\nimport { formatGameTime, getDayOfWeekChinese } from '../utils/gameTime';\nexport default /*@__PURE__*/ _defineComponent({\n    __name: 'GameTimeDisplay',\n    props: {\n        isDarkMode: { type: Boolean, default: false },\n        showWeekDay: { type: Boolean, default: true },\n        format: { default: 'YYYY年MM月DD日 HH:mm' }\n    },\n    setup(__props) {\n        /**\n         * 游戏时间显示组件\n         * 展示游戏内变量时间（年/月/日/时/分），完全由 MVU 变量控制\n         * 非现实时间，与系统时钟无关，随剧情推进而更新\n         */\n        const props = __props;\n        // 游戏时间响应式数据\n        const gameTime = useGameTime();\n        // 格式化时间显示\n        const formattedTime = computed(() => {\n            return formatGameTime(gameTime.value, props.format);\n        });\n        // 星期几\n        const weekDay = computed(() => {\n            return getDayOfWeekChinese(gameTime.value);\n        });\n        return (_ctx, _cache) => {\n            return (_openBlock(), _createElementBlock(\"div\", {\n                class: _normalizeClass([\"game-time-display\", { 'dark': __props.isDarkMode }]),\n                title: \"游戏内时间（由变量控制，非现实时间）\"\n            }, [\n                _createElementVNode(\"div\", _hoisted_1, [\n                    _cache[0] || (_cache[0] = _createElementVNode(\"i\", {\n                        class: \"fa-regular fa-clock\",\n                        \"aria-hidden\": \"true\"\n                    }, null, -1 /* CACHED */)),\n                    _createElementVNode(\"span\", _hoisted_2, _toDisplayString(formattedTime.value), 1 /* TEXT */),\n                    (__props.showWeekDay)\n                        ? (_openBlock(), _createElementBlock(\"span\", _hoisted_3, _toDisplayString(weekDay.value), 1 /* TEXT */))\n                        : _createCommentVNode(\"v-if\", true)\n                ])\n            ], 2 /* CLASS */));\n        };\n    }\n});\n","/* unplugin-vue-components disabled */import script from \"./GameTimeDisplay.vue?vue&type=script&setup=true&lang=ts\"\nexport * from \"./GameTimeDisplay.vue?vue&type=script&setup=true&lang=ts\"\n\nimport \"./GameTimeDisplay.vue?vue&type=style&index=0&id=d650bb28&scoped=true&lang=scss\"\n\nimport exportComponent from \"../../../node_modules/.pnpm/vue-loader@17.4.2_vue@3.5.32_typescript@6.0.0-dev.20250807__webpack@5.105.4/node_modules/vue-loader/dist/exportHelper.js\"\nconst __exports__ = /*#__PURE__*/exportComponent(script, [['__scopeId',\"data-v-d650bb28\"]])\n\nexport default __exports__","/**\n * 游戏初始化工具\n * 负责初始化游戏变量、创建开局楼层、管理世界书条目\n */\n\nimport type { OpeningFormData, SceneEra } from '../types';\n\n/**\n * 根据场景时代获取默认区域名称\n */\nfunction getDefaultRegionNameByEra(era?: SceneEra): string {\n  switch (era) {\n    case 'modern':\n      return '现代都市街区';\n    case 'medieval':\n      return '中世纪城堡';\n    case 'fantasy':\n      return '幻想世界初始地';\n    case 'future':\n      return '未来空间站';\n    case 'ancient':\n      return '古代城镇';\n    default:\n      return '初始场景';\n  }\n}\n\n/**\n * 根据场景时代获取默认区域描述\n */\nfunction getDefaultRegionDescByEra(era?: SceneEra): string {\n  switch (era) {\n    case 'modern':\n      return '繁华的都市街道，高楼林立，人来人往。这里是一切故事的开始。';\n    case 'medieval':\n      return '古老的石制城堡，厚重的城墙见证了无数历史。旗帜在风中飘扬。';\n    case 'fantasy':\n      return '神秘的异世界初始之地，魔法气息弥漫，未知的冒险等待着。';\n    case 'future':\n      return '高科技的未来空间站，金属走廊延伸至远方，全息屏幕闪烁。';\n    case 'ancient':\n      return '古朴的古代城镇，青石板路，传统建筑，时光仿佛在这里静止。';\n    default:\n      return '故事开始的场所，一切冒险的起点。';\n  }\n}\n\n/**\n * 根据场景时代计算初始游戏时间\n * - modern: 现代，使用当前年份（2026年左右）\n * - medieval: 中世纪，约1000-1400年\n * - fantasy: 异世界，使用奇幻风格的日期（如幻想历、精灵历等）\n * - future: 未来，约2077年及以后\n * - ancient: 古代，约公元前或公元初期\n */\nfunction getInitialGameTimeByEra(era?: SceneEra) {\n  const currentYear = new Date().getFullYear();\n  const currentMonth = new Date().getMonth() + 1;\n  const currentDay = new Date().getDate();\n  const currentHour = new Date().getHours();\n  const currentMinute = new Date().getMinutes();\n\n  switch (era) {\n    case 'modern':\n      // 现代：使用当前年份，月份日期可以随机一些变化\n      return {\n        年: currentYear,\n        月: currentMonth,\n        日: currentDay,\n        时: 12,\n        分: 0,\n      };\n\n    case 'medieval':\n      // 中世纪：约1000-1400年，随机选择\n      return {\n        年: 1000 + Math.floor(Math.random() * 400),\n        月: Math.floor(Math.random() * 12) + 1,\n        日: Math.floor(Math.random() * 28) + 1,\n        时: 12,\n        分: 0,\n      };\n\n    case 'fantasy':\n      // 异世界：使用奇幻历法，如\"幻想历\"或自定义年份\n      // 可以是类似\"星历\"、\"魔法历\"的年份格式\n      return {\n        年: 784 + Math.floor(Math.random() * 200), // 幻想历784年，一个典型的奇幻年份\n        月: Math.floor(Math.random() * 12) + 1,\n        日: Math.floor(Math.random() * 28) + 1,\n        时: 12,\n        分: 0,\n      };\n\n    case 'future':\n      // 未来：2077年及以后\n      return {\n        年: 2077 + Math.floor(Math.random() * 50),\n        月: Math.floor(Math.random() * 12) + 1,\n        日: Math.floor(Math.random() * 28) + 1,\n        时: 12,\n        分: 0,\n      };\n\n    case 'ancient':\n      // 古代：约公元前或公元初期（使用负数或较小数字表示）\n      // 如大唐时期约为公元600-900年\n      return {\n        年: 600 + Math.floor(Math.random() * 300),\n        月: Math.floor(Math.random() * 12) + 1,\n        日: Math.floor(Math.random() * 28) + 1,\n        时: 12,\n        分: 0,\n      };\n\n    default:\n      // 默认使用现代时间\n      return {\n        年: currentYear,\n        月: currentMonth,\n        日: currentDay,\n        时: 12,\n        分: 0,\n      };\n  }\n}\n\n/**\n * 获取时代的中文描述，用于在提示词中说明时间背景\n */\nfunction getEraDescription(era?: SceneEra): string {\n  switch (era) {\n    case 'modern':\n      return '现代（公元21世纪）';\n    case 'medieval':\n      return '中世纪（约公元10-14世纪）';\n    case 'fantasy':\n      return '异世界（幻想历）';\n    case 'future':\n      return '未来（2077年后）';\n    case 'ancient':\n      return '古代（约公元6-9世纪）';\n    default:\n      return '现代';\n  }\n}\n\n/** 开局 <maintext> 正文写作要求（与清单、变量约束配合使用） */\nconst OPENING_MAINTEXT_REQUEST = `<request>\n你的任务是继续写\"正在发生的剧情\"，而不是介绍设定。\n\n正文必须遵守以下原则：\n\n1. 只写当前场景中正在发生的事\n- 只描写人物、动作、对白、环境、气氛、可观察到的变化\n- 优先写具体细节，不写抽象总结\n\n2. 禁止规则说明腔\n- 禁止在正文中解释世界规则、区域规则、个人规则的定义、机制、条件、作用范围与结论\n- 禁止出现\"该规则规定……\"\"她知道规则……\"\"只要……就会……\"\"她无法违抗，因为……\"这类说明句\n- 禁止把后台资料、规则名、规则描述直接翻译成旁白\n\n3. 规则只通过自然表现呈现\n- 规则效果只能通过人物下意识动作、习惯反应、场景秩序、他人默认接受来体现\n- 不要写\"规则生效了\"，要写\"在这个场景里，人就是这么做的\"\n\n4. 人物先于规则\n- 先写\"这个人此刻怎么反应\"，再让读者从反应里感受到规则存在\n- 角色不能成为规则的复读器或说明书\n\n5. 禁止分析与讲解\n- 不写研究式、解释式、总结式语言\n- 不写作者说明，不写设定介绍，不写机制剖析\n- 不使用\"世界观中\"\"按照规则\"\"由于某设定\"这类跳出场景的话\n\n6. 语言要求\n- 语言自然、顺滑、贴近现场\n- 少用大词、空话、判断句\n- 尽量使用白描：让读者看见，而不是听旁白解释\n\n7. 当本回合存在新增 / 修改 / 删除规则时\n- <maintext> 必须先呈现该规则在当前场景中的即时显化，再继续后续叙事\n- 即时显化只写当前人物、环境、物件、流程中立刻可见的变化\n- 禁止跳过显化阶段，直接把新规则后的世界写成「仿佛一直如此」\n- 禁止解释规则机制，禁止出现「因为规则……所以……」这类说明句\n</request>`;\n\n/**\n * 1. 初始化游戏变量（写入0层）\n * 注意：使用 updateVariablesWith 确保原子性更新，避免覆盖其他数据\n */\nexport async function initializeGameVariables(formData: OpeningFormData): Promise<boolean> {\n  try {\n    // 检查0层变量是否存在（updateVariablesWith 会自动创建）\n    try {\n      getVariables({ type: 'message', message_id: 0 });\n    } catch {\n      // 0层消息不存在，updateVariablesWith 会在更新时创建\n    }\n\n    // 使用 updateVariablesWith 更新0层变量\n    await updateVariablesWith(\n      vars => {\n        // 确保基础结构存在\n        if (!vars) vars = {};\n        if (!vars.stat_data) vars.stat_data = {};\n\n        // 初始化游戏状态\n        if (!vars.stat_data.gameStatus) {\n          vars.stat_data.gameStatus = {\n            phase: 'opening',\n            turn: 0,\n            lastUpdated: new Date().toISOString(),\n          };\n        }\n\n        // 初始化玩家信息\n        vars.stat_data.player = {\n          name: formData.playerName || '玩家',\n          settings: {\n            difficulty: formData.gameDifficulty,\n            enableWorldRules: formData.enableWorldRules,\n            enableRegionalRules: formData.enableRegionalRules,\n            enablePersonalRules: formData.enablePersonalRules,\n          },\n        };\n\n        // 规则与角色仅使用中文「世界规则」「角色档案」等结构，不在此写入英文数组，避免与 MVU / 第二 API 混淆\n\n        // 初始化元数据\n        vars.stat_data.meta = {\n          createdAt: new Date().toISOString(),\n          updatedAt: new Date().toISOString(),\n          version: '1.0.0',\n        };\n\n        // 保存开局配置\n        vars.stat_data.openingConfig = formData;\n\n        // 根据场景时代初始化游戏时间\n        const initialGameTime = getInitialGameTimeByEra(formData.sceneEra);\n        vars.stat_data.游戏时间 = initialGameTime;\n        console.log(`✅ [gameInitializer] 游戏时间已初始化为 ${initialGameTime.年}年${initialGameTime.月}月${initialGameTime.日}日（时代：${formData.sceneEra || '默认'})`);\n\n        // 初始化默认区域（使用开局选择的场景）\n        // formData.sceneDescription 格式: \"场景名称：场景描述\"\n        let defaultRegionName: string;\n        let defaultRegionDesc: string;\n\n        if (formData.sceneDescription?.trim()) {\n          // 解析场景描述，格式是 \"名称：描述\"\n          const sceneDesc = formData.sceneDescription.trim();\n          const colonIndex = sceneDesc.indexOf('：');\n          if (colonIndex > 0) {\n            defaultRegionName = sceneDesc.substring(0, colonIndex);\n            defaultRegionDesc = sceneDesc.substring(colonIndex + 1);\n          } else {\n            // 如果没有分隔符，就用整个描述作为名称\n            defaultRegionName = sceneDesc;\n            defaultRegionDesc = '故事开始的场所';\n          }\n        } else {\n          // 回退：根据时代生成默认区域\n          defaultRegionName = getDefaultRegionNameByEra(formData.sceneEra);\n          defaultRegionDesc = getDefaultRegionDescByEra(formData.sceneEra);\n        }\n\n        vars.stat_data.区域规则 = {\n          ['初始区域']: {\n            名称: defaultRegionName,\n            效果描述: defaultRegionDesc,\n            状态: '生效中',\n            细分规则: {},\n          },\n        };\n        console.log(`✅ [gameInitializer] 默认区域已创建：${defaultRegionName}`);\n\n        console.log('✅ [gameInitializer] 0层变量初始化完成');\n        return vars;\n      },\n      { type: 'message', message_id: 0 },\n    );\n\n    console.log('✅ [gameInitializer] 成功初始化0层游戏变量');\n    return true;\n  } catch (error) {\n    console.error('❌ [gameInitializer] 初始化0层游戏变量失败:', error);\n    return false;\n  }\n}\n\n/**\n * 根据表单数据构建开局提示词（供 createOpeningStoryMessage 与「跳过创建」分支共用）\n */\nfunction buildOpeningPromptContent(formData: OpeningFormData): string {\n  const sceneDesc = formData.sceneDescription || '神秘的未知场所';\n  const openingDetail = String(formData.openingSceneDetail ?? '').trim();\n\n  // 获取场景时代的时间背景描述\n  const eraDesc = getEraDescription(formData.sceneEra);\n  const initialGameTime = getInitialGameTimeByEra(formData.sceneEra);\n  const timeDescription = `${initialGameTime.年}年${initialGameTime.月}月${initialGameTime.日}日`;\n\n  const rules = (formData.selectedRules ?? []) as Array<{ name: string; desc: string; isCustom?: boolean }>;\n  const presetRules = rules.filter(r => !r.isCustom);\n  const customRules = rules.filter(r => r.isCustom);\n  const characters = formData.characters ?? [];\n\n  const ruleLinesForNarrative: string[] = [];\n  if (presetRules.length > 0) {\n    ruleLinesForNarrative.push(\n      ...presetRules.map((r: { name: string; desc: string }) => `【预设世界规则】${r.name}：${r.desc}`),\n    );\n  }\n  if (customRules.length > 0) {\n    ruleLinesForNarrative.push(\n      ...customRules.map((r: { name: string; desc: string }) => `【自定义世界规则】${r.name}：${r.desc}`),\n    );\n  }\n\n  const charLinesForNarrative = characters.map((c: { name: string; gender: string; desc: string }) => {\n    const gender = c.gender === 'female' ? '女' : c.gender === 'male' ? '男' : '其他';\n    return `【角色】${c.name}（${gender}）：${c.desc}`;\n  });\n\n  // 编号清单：明确要求 <maintext> 逐条体现（便于变量与第二 API 对齐）\n  const checklist: string[] = [];\n  let n = 1;\n  checklist.push(`${n}. 开局地点与整体氛围必须与下列场景设定一致：${sceneDesc}`);\n  n += 1;\n\n  // 添加时代/时间背景要求\n  if (formData.sceneEra) {\n    checklist.push(`${n}. 故事必须发生在${eraDesc}，时间设定为${timeDescription}，场景中的元素、人物着装、技术/魔法水平、语言风格必须与该时代背景一致`);\n    n += 1;\n  }\n\n  if (openingDetail) {\n    checklist.push(`${n}. 开场时刻、空间与情节须体现以下补充（不可省略）：${openingDetail}`);\n    n += 1;\n  }\n  for (const r of [...presetRules, ...customRules]) {\n    checklist.push(\n      `${n}. 世界规则「${r.name}」（名称仅供变量对齐）：正文须呈现与下列效果相容的现场，只通过人物言行与场景自然体现，禁止规则说明腔、禁止在正文复述规则名或条文；——${String(r.desc).replace(/\\s+/g, ' ').trim()}`,\n    );\n    n += 1;\n  }\n  for (const c of characters) {\n    const gender = c.gender === 'female' ? '女' : c.gender === 'male' ? '男' : '其他';\n    checklist.push(\n      `${n}. 角色「${c.name}」（${gender}）：正文须有具体出场或互动，用现场细节体现下列特质，禁止复述设定句、禁止说明书式介绍；——${String(c.desc).replace(/\\s+/g, ' ').trim()}`,\n    );\n    n += 1;\n  }\n\n  const enableBits: string[] = [];\n  if (formData.enableWorldRules) enableBits.push('世界级规则已启用');\n  if (formData.enableRegionalRules) enableBits.push('区域规则已启用');\n  if (formData.enablePersonalRules) enableBits.push('个人规则已启用');\n  const enableLine = enableBits.length > 0 ? enableBits.join('；') : '规则开关按表单默认';\n\n  // 构建包含时代信息的时间描述\n  const timeInfoLines = formData.sceneEra\n    ? [`【时代背景】${eraDesc}`, `【故事时间】${timeDescription}`]\n    : [];\n\n  const narrativeBlock = [\n    `【规则开关】${enableLine}`,\n    '',\n    ...timeInfoLines,\n    ...(timeInfoLines.length > 0 ? [''] : []),\n    '—— 以下为配置摘要（清单见下节；<maintext> 须用现场叙事落实，写法遵守「二（续）」）——',\n    ...ruleLinesForNarrative,\n    ...charLinesForNarrative,\n  ].join('\\n');\n\n  const checklistBlock = checklist.join('\\n');\n\n  const jsonPatchLines: string[] = [];\n  for (const r of rules) {\n    const ruleValue = {\n      名称: r.name,\n      效果描述: String(r.desc).replace(/\\s+/g, ' ').trim(),\n      状态: '生效中',\n      细分规则: {} as Record<string, unknown>,\n      适用对象: '全局',\n      标记: '世界级',\n    };\n    jsonPatchLines.push(\n      `  { \"op\": \"replace\", \"path\": \"/世界规则/${r.name}\", \"value\": ${JSON.stringify(ruleValue)} }`,\n    );\n  }\n  characters.forEach((c: { name: string; desc: string }, i: number) => {\n    const chrValue = {\n      姓名: c.name,\n      状态: '出场中',\n      描写: String(c.desc).replace(/\\s+/g, ' ').trim(),\n      当前内心想法: '',\n      性格: {} as Record<string, string>,\n      性癖: {} as Record<string, string>,\n      敏感部位: {} as Record<string, string>,\n      隐藏性癖: '',\n      身体信息: {\n        年龄: 18,\n        身高: 165,\n        体重: 50,\n        三围: 'B86 W58 H88',\n        体质特征: '普通',\n      },\n      数值: { 好感度: 30, 发情值: 20, 性癖开发值: 10 },\n      当前综合生理描述: '',\n    };\n    jsonPatchLines.push(\n      `  { \"op\": \"replace\", \"path\": \"/角色档案/CHR-${String(i + 1).padStart(3, '0')}\", \"value\": ${JSON.stringify(chrValue)} }`,\n    );\n  });\n  const jsonPatchInner = jsonPatchLines.join(',\\n');\n\n  return `请根据以下开局配置生成**第一回合 AI 回复**（开场白 + 选项 + 总结 + 变量补丁），使正文与变量初始化一致。\n\n## 一、配置摘要\n${narrativeBlock}\n\n## 二、<maintext> 必须逐条覆盖的清单（共 ${checklist.length} 条，缺一不可）\n${checklistBlock}\n\n## 二（续）、正文写作要求（<maintext> 须严格遵守）\n${OPENING_MAINTEXT_REQUEST}\n\n## 三、输出格式（顺序固定；所有标签必须成对闭合，禁止只写开标签）\n1. 先输出 <maintext>…</maintext>：写成完整叙事段落，**同时**满足上文「二」的清单与「二（续）」；以便后续变量更新能对应正文。\n2. 再输出 <option>…</option>：内含多行，以「A.」「B.」「C.」开头；**必须**以 </option> 闭合。\n3. 再输出 <sum>…</sum>：一句话概括开局；**必须**以 </sum> 闭合。\n4. 最后输出 <UpdateVariable>…</UpdateVariable>：须符合下方「## 四、变量补丁约束」。**本局开局提示里已给出示例 Patch，若 user 楼层已写入同名路径，你方必须用 replace 覆盖，勿用 insert 顶同名路径。** 按实际剧情微调数值与描写。\n\n## 四、变量补丁（须与 MVU 解析一致）\n- **总原则**：\\`<JSONPatch>\\` 内为合法 JSON 数组。**本界面与 MVU 解析要求：对「世界规则 / 角色档案」的整条更新以 replace 为主**；**delta**/**insert**/**remove**/**move** 仅在不与下文字段硬约束冲突时使用（以 MVU 实际支持为准）。若与世界书/上下文注入冲突，以已注入说明为准。\n- **路径（中文根）**：世界规则 **/世界规则/<规则名>**；角色 **/角色档案/CHR-xxx**（顺序与开局一致）。**禁止**用 **/characters**、**world_rules** 等英文平行根。\n- **开局特判（重要）**：同一聊天里 **user 消息可能已含同名路径的初始化**。对 **/世界规则/…**、**/角色档案/CHR-001** 等 **已存在** 的路径：**一律使用 \\`\"op\": \"replace\"\\` 写入完整 value**，**禁止**对已有对象路径使用 **insert**（易导致 Patch 失败且不更新角色）。\n- **世界规则 value**：须含 **名称、效果描述、状态、细分规则、适用对象、标记**（**细分规则** 可为 \\`{}\\`）；**状态** 常用「生效中」；**标记** 为单个字符串。\n- **角色档案 value（类型硬约束，违反则变量无法写入）**：顶层键须齐全：**姓名、状态、描写、当前内心想法、性格、性癖、敏感部位、隐藏性癖、身体信息、数值、当前综合生理描述**。\n  - **性格**：**必须为 JSON 对象** \\`{ \"名称\": \"描述\" }\\`（如 \\`{\"傲娇\": \"口是心非\"}\\`），无条目则 \\`{}\\`；**兼容**旧版字符串数组。\n  - **性癖**：\\`{ \"名称\": { \"等级\": 数字, \"细节描述\": \"…\", \"自我合理化\": \"…\" } }\\`；**兼容**旧版 \\`{ \"名称\": \"描述字符串\" }\\`。\n  - **敏感部位**：\\`{ \"名称\": { \"敏感等级\": 数字, \"生理反应\": \"…\", \"开发细节\": \"…\" } }\\`；**兼容**旧版 \\`{ \"名称\": \"描述字符串\" }\\`。\n  - **隐藏性癖**：**必须是字符串**（无则写 \\`\"\"\\`）。**禁止**写成 \\`{}\\` 或对象。\n  - **身体信息**：年龄/身高/体重为数字；**三围**为**字符串**（如 \\`\"B86 W58 H88\"\\`）或对象 \\`{\"B\":86,\"W\":58,\"H\":88}\\`；**体质特征**为字符串。\n  - **数值**：**好感度、发情值、性癖开发值** 为数字；**禁止**用「性癖开发度」键名。\n  - **状态**：仅 **「出场中」** 或 **「暂时退场」**；勿把长剧情写入「状态」。\n- **正文与变量一致**：正文若已写生理/情绪/好感等，须在「数值」「当前综合生理描述」（必要时「当前内心想法」）中反映。\n- **格式**：勿在 \\`<JSONPatch>\\` 数组外夹带假 JSON；\\`<Analysis>\\` 语言与篇幅若角色卡另有规定，从其规定。\n\n## 五、玩家行动后的强制变量更新要求（**重要**）\n玩家已发送第一条行动消息。AI 在回复本次玩家输入时，**必须在回复末尾输出完整的变量更新块**。\n\n**角色档案完整性检查清单**（每个角色必须满足，禁止留空）：\n- **姓名**：已确定的角色名\n- **状态**：「出场中」或「暂时退场」\n- **描写**：角色的外貌、衣着、当前姿态等描写\n- **当前内心想法**：角色当前的心理活动\n- **性格**：至少一条性格特征，如 \\`{\"害羞\": \"容易脸红，不敢直视他人\"}\\`\n- **性癖**：至少一条；推荐嵌套如 \\`{\"被注视\": {\"等级\":1,\"细节描述\":\"…\",\"自我合理化\":\"…\"}}\\`，或旧版 \\`{\"被注视\": \"被人注视时会感到紧张\"}\\`\n- **敏感部位**：至少一处；推荐嵌套如 \\`{\"耳朵\": {\"敏感等级\":2,\"生理反应\":\"…\",\"开发细节\":\"…\"}}\\`，或旧版 \\`{\"耳朵\": \"被轻触时会颤抖\"}\\`\n- **隐藏性癖**：字符串，可为空字符串但必须是字符串类型\n- **身体信息**：年龄、身高、体重、三围、体质特征\n- **数值**：好感度、发情值、性癖开发值（均须为数字）\n- **当前综合生理描述**：角色当前的身体状态描述\n\n**强制要求**：\n1. 每个角色上述字段**必须全部存在**，不能为空对象或缺失\n2. 性格、性癖、敏感部位**每个至少包含一条**（不得为空对象 \\`{}\\`）\n3. 回复末尾必须包含完整的 \\`<UpdateVariable>\\` 块，内含 \\`<Analysis>\\` 和 \\`<JSONPatch>\\`\n4. 如有任何字段不满足，本次回复视为不完整，需补充修正\n\n<maintext>\n[正在发生的现场剧情，须覆盖清单全部条目；写法遵守「二（续）」]\n</maintext>\n\n<option>\nA. [选项A]\nB. [选项B]\nC. [选项C]\n</option>\n\n<sum>[一句话总结]</sum>\n\n<UpdateVariable>\n<Analysis>\n- 初始化世界规则和角色档案\n</Analysis>\n<JSONPatch>\n[\n${jsonPatchInner}\n]\n</JSONPatch>\n</UpdateVariable>`;\n}\n\n/**\n * 2. 准备开局提示词（不写入聊天楼层）\n * 实际 user 楼层由 App.vue 在调用 generate 前统一创建并做 MVU 解析，避免与 gameInitializer 重复写入导致多条玩家楼层。\n * 若检测到已有第 1 层消息，仍返回 promptContent，并异步尝试更新编年史。\n */\nexport async function createOpeningStoryMessage(formData: OpeningFormData): Promise<{success: boolean; promptContent?: string}> {\n  try {\n    const promptContent = buildOpeningPromptContent(formData);\n\n    try {\n      const existingMessages = getChatMessages(1);\n      if (existingMessages && existingMessages.length > 0) {\n        console.log('⚠️ [gameInitializer] 1层消息已存在，仅返回 promptContent 供 generate 使用');\n        setTimeout(async () => {\n          try {\n            const { checkAndUpdateChronicle } = await import('./chronicleUpdater');\n            await new Promise(resolve => setTimeout(resolve, 500));\n            await checkAndUpdateChronicle();\n          } catch (error) {\n            console.error('❌ [gameInitializer] 更新编年史失败:', error);\n          }\n        }, 500);\n        return { success: true, promptContent };\n      }\n    } catch {\n      /* 第 1 层不存在等，忽略 */\n    }\n\n    console.log('✅ [gameInitializer] 开局提示词已准备');\n    console.log('📝 [gameInitializer] 提示词内容预览:', promptContent.substring(0, 200) + '...');\n    return { success: true, promptContent };\n  } catch (error) {\n    console.error('❌ [gameInitializer] 准备开局提示词失败:', error);\n    return { success: false };\n  }\n}\n\n/**\n * 重置游戏（用于重新开始）\n * 清除0层变量并重新开始\n */\nexport async function resetGame(): Promise<boolean> {\n  try {\n    // 重置0层变量\n    await replaceVariables(\n      {\n        stat_data: {},\n        display_data: {},\n        delta_data: {},\n      },\n      { type: 'message', message_id: 0 },\n    );\n\n    console.log('✅ [gameInitializer] 游戏已重置');\n    return true;\n  } catch (error) {\n    console.error('❌ [gameInitializer] 重置游戏失败:', error);\n    return false;\n  }\n}\n\n/**\n * 检查是否是新游戏（0层且无1层消息）\n */\nexport function isNewGame(): boolean {\n  try {\n    const lastMessageId = getLastMessageId();\n    if (lastMessageId > 0) {\n      return false;\n    }\n\n    // 检查0层是否有数据\n    try {\n      const vars = getVariables({ type: 'message', message_id: 0 });\n      if (vars && vars.stat_data && Object.keys(vars.stat_data).length > 0) {\n        return false;\n      }\n    } catch (err) {\n      // 0层变量不存在，认为是新游戏\n    }\n\n    return true;\n  } catch (error) {\n    console.error('❌ [gameInitializer] 检查游戏状态失败:', error);\n    return true;\n  }\n}\n","export type IframeHeightFixOptions = {\n  minHeightPx: number; // Minimum height to keep (px)\n  selector: string; // iframe selector in parent document\n  intervalMs: number; // Poll interval\n};\n\nconst DEFAULTS: IframeHeightFixOptions = {\n  minHeightPx: 600,\n  selector: 'iframe[id^=\"TH-message--\"]',\n  intervalMs: 200,\n};\n\nfunction safeSetIframeMinHeight(\n  parentDoc: Document,\n  options: IframeHeightFixOptions,\n) {\n  const HEIGHT = `${options.minHeightPx}px`;\n  const iframes = parentDoc.querySelectorAll<HTMLIFrameElement>(options.selector);\n  if (iframes.length === 0) return;\n\n  for (const iframe of Array.from(iframes)) {\n    // Keep a minimum height, but don't force a fixed height.\n    iframe.style.setProperty('min-height', HEIGHT, 'important');\n    iframe.style.setProperty('max-height', 'none', 'important');\n    // If we previously forced a fixed height, remove it so larger sizes can work.\n    iframe.style.removeProperty('height');\n  }\n}\n\n/**\n * Keep host iframe from shrinking into a narrow strip.\n * This code runs inside the iframe, but modifies `window.parent.document`.\n *\n * If parent is cross-origin, it will silently no-op.\n */\nexport function startIframeHeightFix(\n  opts?: Partial<IframeHeightFixOptions>,\n): () => void {\n  const options: IframeHeightFixOptions = { ...DEFAULTS, ...(opts ?? {}) };\n\n  // If already started in the same iframe instance, disconnect first.\n  if ((window as any).__thHeightFixIntervalId) {\n    clearInterval((window as any).__thHeightFixIntervalId);\n    (window as any).__thHeightFixIntervalId = null;\n  }\n\n  const parentWin = window.parent;\n  let parentDoc: Document | null = null;\n  try {\n    parentDoc = parentWin?.document ?? null;\n  } catch {\n    parentDoc = null;\n  }\n\n  if (!parentDoc) return () => {};\n\n  const enforce = () => {\n    try {\n      safeSetIframeMinHeight(parentDoc!, options);\n    } catch {\n      // Ignore (host may re-render and detach nodes)\n    }\n  };\n\n  // Poll because host writes styles repeatedly after \"confirm\".\n  enforce();\n  const intervalId = window.setInterval(enforce, options.intervalMs);\n  (window as any).__thHeightFixIntervalId = intervalId;\n\n  return () => {\n    try {\n      clearInterval(intervalId);\n    } finally {\n      if ((window as any).__thHeightFixIntervalId === intervalId) {\n        (window as any).__thHeightFixIntervalId = null;\n      }\n    }\n  };\n}\n\n","import { defineComponent as _defineComponent } from 'vue';\nimport { createElementVNode as _createElementVNode, toDisplayString as _toDisplayString, openBlock as _openBlock, createElementBlock as _createElementBlock, createCommentVNode as